body {
      font-size: 16px !important;
      line-height: 1.6 !important;
      scroll-behavior: smooth !important;
      font-family: 'Pretendard', sans-serif !important;
    }

    /* 바닐라 페이드 슬라이더 및 트랜지션 CSS */
    .list_kv_img .img-wrap {
      position: absolute;
      inset: 0;
      display: block;
      width: 100%;
      height: 100%;
      opacity: 0;
      z-index: 0;
      overflow: hidden;
      /* active/last-active 클래스가 해제되면 3초간 대기 후 즉시 opacity와 z-index를 0으로 초기화합니다 */
      transition: opacity 0s 3s, z-index 0s 3s;
    }
    .list_kv_img .img-wrap.active {
      opacity: 1;
      z-index: 20;
      /* active 활성화 시 3초 동안 부드럽게 opacity를 1로 채웁니다 */
      transition: opacity 3s ease-in-out, z-index 0s 0s;
    }
    .list_kv_img .img-wrap.last-active {
      opacity: 1;
      z-index: 10;
      /* last-active 상태(이전 이미지)는 3초 동안 선명함(opacity:1)을 유지하다가 3초 후에 즉시 꺼집니다 */
      transition: opacity 0s 3s, z-index 0s 3s;
    }
    .list_kv_img .img-wrap img {
      width: 100%;
      height: 100%;
      object-fit: cover;
      object-position: center;
      transform-origin: top center;
      transform: scale(1.3);
      /* active가 풀리고 완전히 페이드아웃(3초)된 후인 3.5초 뒤에 즉시 scale 1.3으로 복구시켜 튕김을 감춥니다 */
      transition: transform 0s 3.5s;
    }
    .list_kv_img .img-wrap.active img {
      transform: scale(1);
      transition: transform 7.5s ease-out;
    }
    @media (max-width: 1024px) {
      .list_kv_img .img-wrap {
        height: 570px;
      }
    }

